final:
module RefModule (  
    input wire S,  
    input wire R,  
    input wire clk,  
    output reg Q  
);  
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin  
        if (S && !R)  
            Q <= 1;  
        else if (!S && R)  
            Q <= 0;  
        // if both S and R are 0, Q retains its value  
    end  
endmodule
